import { useState, useEffect } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { supabase } from './supabaseClient';
import Auth from './Auth';
import SavedDupes from './SavedDupes';

function App() {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState("");
  const [session, setSession] = useState(null);

  // Shtojmë një state për të treguar nëse po ruhet
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });
    supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
  }, []);

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setLoading(true);
    setResponse(""); // Pastro përgjigjen e vjetër

    try {
      const res = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ message: input }),
      });

      if (!res.ok) {
        throw new Error(`HTTP error! status: ${res.status}`);
      }

      const data = await res.json();
      setResponse(data.reply);
    } catch (error) {
      console.error("Error fetching data:", error);
      setResponse("Ndodhi një gabim. Sigurohu që backend-i (Python) është i ndezur.");
    } finally {
      setLoading(false);
    }
  };

  // KJO ËSHTË MAGJIA E RE: Funksioni për të ruajtur automatikisht
  const handleAutoSave = async () => {
    if (!session) return;
    setSaving(true);

    const { error } = await supabase
      .from('saved_dupes')
      .insert([
        { 
          user_id: session.user.id, 
          original_product: input, // Merr pyetjen që bëri useri
          dupe_product: "Sugjerim nga Inteligjenca Artificiale" // Etiketë automatike
        }
      ]);

    if (error) {
      alert("Gabim gjatë ruajtjes: " + error.message);
    } else {
      alert("U ruajt me sukses! Shiko listën më poshtë.");
      // Mundësisht pastro fushën e kërkimit për një produkt të ri
      setInput(""); 
    }
    setSaving(false);
  };

  return (
    <div style={{ maxWidth: "800px", margin: "auto", padding: "40px", fontFamily: "sans-serif" }}>
      <h1 style={{ textAlign: "center", color: "#333" }}>GlowAI 🧴✨</h1>

      {!session ? (
        <Auth />
      ) : (
        <>
          <div style={{ marginBottom: "50px" }}>
            <h2 style={{ fontSize: "1.2rem", color: "#555" }}>Kërko për Dupes:</h2>
            <textarea
              rows="4"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="E.g., Find a drugstore dupe for Drunk Elephant Protini Cream..."
              style={{ width: "100%", padding: "12px", borderRadius: "8px", border: "1px solid #ccc", fontSize: "16px", fontFamily: "inherit" }}
            />
            <br />

            <button 
              onClick={handleSubmit} 
              disabled={loading}
              style={{ marginTop: "10px", padding: "10px 20px", backgroundColor: loading ? "#ccc" : "#000", color: "#fff", border: "none", borderRadius: "5px", cursor: loading ? "not-allowed" : "pointer", fontSize: "16px" }}
            >
              {loading ? "Duke Analizuar..." : "Gjej Dupes"}
            </button>

            {response && (
              <div style={{ marginTop: "30px", padding: "20px", border: "1px solid #eee", borderRadius: "8px", backgroundColor: "#fcfcfc", lineHeight: "1.6" }}>
                <h3 style={{ marginTop: 0 }}>Analiza:</h3>
                <ReactMarkdown remarkPlugins={[remarkGfm]}>
                  {response}
                </ReactMarkdown>

                {/* BUTONI I RI AUTOMATIK */}
                <button 
                  onClick={handleAutoSave}
                  disabled={saving}
                  style={{ marginTop: "20px", padding: "10px 15px", backgroundColor: "#28a745", color: "white", border: "none", borderRadius: "5px", cursor: "pointer", fontSize: "15px", display: "block", width: "100%" }}
                >
                  {saving ? "Po ruhet..." : "💾 Ruaj këtë kërkim në listën time"}
                </button>
              </div>
            )}
          </div>

          <hr style={{ border: "0", height: "1px", backgroundColor: "#ddd", marginBottom: "40px" }} />

          {/* Seksioni i vjetër i ruajtjes manuale poshtë (në rast se duan të shtojnë vetë diçka) */}
          <SavedDupes session={session} />
        </>
      )}
    </div>
  );
}

export default App;
